        isAdmin: json['is_admin'] ?? false,
        isManager: json['is_manager'] ?? false,
        isEmployee: json['is_employee'] ?? false,
        isBoss: json['is_boss'] ?? false,
        user: json['user'] != null ? UserModel.fromJson(json['user']) : null);
  }

