              // margin: const EdgeInsets.symmetric(horizontal: 20, vertical: 20),
              decoration: BoxDecoration(
                gradient: const LinearGradient(
                  transform: GradientRotation(pi / 4),
                  colors: ColorPallete.background,
                  begin: Alignment.topLeft,
