                          color: Colors.white.withOpacity(0.3),
                          blurRadius: 12,
                          spreadRadius: 2,
                        )
                      ]
                    : null,
                gradient: LinearGradient(
                    colors: widget.isSelected
                        ? ColorPallete.buttonGradient
