      color: Colors.transparent,
      child: Container(
        decoration: BoxDecoration(
          borderRadius: BorderRadius.circular(10),
          gradient: const LinearGradient(
              colors: ColorPallete.background2,
              begin: Alignment.bottomCenter,
              end: Alignment.topCenter),
        ),
        padding: const EdgeInsets.all(20),
        constraints: const BoxConstraints(
            maxWidth: 400, maxHeight: 400, minHeight: 400, minWidth: 400),
        child: SingleChildScrollView(
          child: Column(
            children: [
              SelectableText("Welcome Back",
                  style: Theme.of(context)
                      .textTheme
                      .titleLarge
                      ?.copyWith(color: ColorPallete.white)),
              const SizedBox(height: 20),
              Form(
                  key: formKey,
                  child: Column(
                    mainAxisAlignment: MainAxisAlignment.spaceBetween,
                    children: [
                      TextFormField(
                        controller: emailController,
                        style: Theme.of(context).textTheme.bodyMedium,
                        decoration: const InputDecoration(
                          label: Text("Email"),
                        ),
                      ),
                      const SizedBox(height: 20),
                      TextFormField(
                        controller: passwordController,
                        obscureText: isPasswordVisible,
                        style: Theme.of(context).textTheme.bodyMedium,
                        decoration: InputDecoration(
                            label: const Text("Password"),
                            suffixIcon: IconButton(
                                onPressed: () {
                                  setState(() {
                                    isPasswordVisible = !isPasswordVisible;
                                  });
                                },
                                icon: Icon(isPasswordVisible
                                    ? Icons.visibility
                                    : Icons.visibility_off))),
                        keyboardType: TextInputType.visiblePassword,
                      ),
                      const SizedBox(height: 20),
                      BlocConsumer<AuthBloc, AuthState>(
                        listener: (context, state) {
                          if (state is AuthFailure) {
                            ScaffoldMessenger.of(context).showSnackBar(
                                SnackBar(content: Text(state.message)));
                          } else if (state is AuthSignInSuccess) {
                            getIt<User>().user = state.auth.userEntity;
                            if (getIt<User>().employee != null &&
                                getIt<User>().organisation != null) {
                              context.go(Dashboard.routePath);
                            } else {
                              context.go(RegisterCompanyPage.routePath);
                            }
                          }
                        },
                        builder: (context, state) {
                          if (state is AuthLoading) {
                            return const Center(
                                child: CircularProgressIndicator());
                          } else {
                            return AuthButton(
                              width: 100,
                              height: 50,
                              text: "Sign In",
                              onpressed: () {
                                if (formKey.currentState!.validate()) {
                                  context.read<AuthBloc>().add(SignInEvent(
                                      signInParams: SignInParams(
                                          email: emailController.text,
                                          hashedPassword:
                                              passwordController.text)));
                                }
                              },
                            );
                          }
                        },
                      ),
                      RichText(
                          text: TextSpan(
                              text: "Don't have an account? ",
                              style: Theme.of(context).textTheme.bodyMedium,
                              children: [
                            TextSpan(
                                recognizer: TapGestureRecognizer()
                                  ..onTap = () {
                                    context.pop();
                                    showDialog(
                                        context: context,
                                        builder: (context) =>
                                            const SignUpDialog());
                                  },
                                text: "Sign Up",
                                style: Theme.of(context)
                                    .textTheme
                                    .bodyMedium
                                    ?.copyWith(
                                        color: const Color.fromARGB(
                                            255, 43, 173, 254)))
                          ]))
                    ],
                  ))
            ],
          ),
        ),
      ),
    );
  }
}

